SELECT id, name, mobile_number, email, role, is_active, created_at, updated_at
FROM users
WHERE id = #{id}

SELECT id, name, mobile_number, email, role, is_active, created_at, updated_at
FROM users
WHERE mobile_number = #{mobileNumber}

SELECT CASE WHEN COUNT(*) > 0 THEN TRUE ELSE FALSE END
FROM users
WHERE mobile_number = #{mobileNumber}

SELECT CASE WHEN COUNT(*) > 0 THEN TRUE ELSE FALSE END
FROM users
WHERE email = #{email}
